  ('bookkeeper-moex-01255', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行營利事業所得稅查核準則之規定，副產品之估價以： 實際成本為準；無成本可資核計者，以時價為準 實際成本為準；無成本可資核計者，以時價減除銷售費用之價格為準 時價為準 平均售價減除銷售費用之價格為準', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
